const outputBinary = {};

function cloneBinary(binary, fileName, fallbackMimeType) {
  if (!binary) return null;
  return {
    ...binary,
    fileName,
    mimeType: String(binary.mimeType ?? fallbackMimeType ?? '').trim() || fallbackMimeType,
  };
}

function addTextBinary(propertyName, fileName, text, mimeType) {
  const value = String(text ?? '').trim();
  if (!value) return false;
  outputBinary[propertyName] = {
    data: Buffer.from(value, 'utf8').toString('base64'),
    fileName,
    mimeType,
  };
  return true;
}

const requirementsBinary = cloneBinary(inputBinary.requirements, 'requirements/requirements.md', 'text/markdown')
  ?? (addTextBinary('bundleRequirements', 'requirements/requirements.md', json.finalRequirements ?? '', 'text/markdown') ? outputBinary.bundleRequirements : null);
if (requirementsBinary && !outputBinary.bundleRequirements) outputBinary.bundleRequirements = requirementsBinary;

const designBinary = cloneBinary(inputBinary.design, 'design/design.excalidraw.json', 'application/json')
  ?? (addTextBinary('bundleDesign', 'design/design.excalidraw.json', json.finalDesignExcalidraw ?? json.finalDesign ?? '', 'application/json') ? outputBinary.bundleDesign : null);
if (designBinary && !outputBinary.bundleDesign) outputBinary.bundleDesign = designBinary;

const apiBinary = cloneBinary((inputBinary.api ?? inputBinary.openapiSpec), 'api/openapi.yaml', 'application/yaml')
  ?? (addTextBinary('bundleApi', 'api/openapi.yaml', json.finalOpenapiYaml ?? '', 'application/yaml') ? outputBinary.bundleApi : null);
if (apiBinary && !outputBinary.bundleApi) outputBinary.bundleApi = apiBinary;

const required = ['bundleRequirements', 'bundleDesign', 'bundleApi'];
const missing = required.filter((property) => !outputBinary[property]);
if (missing.length) {
  throw new Error('Missing required base artifacts: ' + missing.join(', '));
}

return [{
  json,
  binary: outputBinary,
}];

const item = $input.first() ?? { json: {}, binary: {} };
const json = { ...(item.json ?? {}) };
const binary = { ...(item.binary ?? {}) };

const moduleFields = ['backendZip', 'frontendZip', 'infrastructureZip', 'testsZip'];
for (const field of moduleFields) {
  const file = binary[field];
  if (!file) {
    throw new Error('Missing uploaded ZIP field: ' + field);
  }
  const fileName = String(file.fileName ?? `${field}.zip`).replace(/\\/g, '/');
  binary[field] = {
    ...file,
    fileName,
    mimeType: 'application/zip',
    fileExtension: 'zip',
  };
}

return [{ json, binary }];

const item = $input.first() ?? { json: {}, binary: {} };
const json = { ...(item.json ?? {}) };
const inputBinary = { ...(item.binary ?? {}) };
const outputBinary = {};

const moduleName = 'backend';

for (const [key, entry] of Object.entries(inputBinary)) {
  if (!entry || typeof entry !== 'object') continue;

  const directory = String(entry.directory ?? '')
    .replace(/\\/g, '/')
    .replace(/^\/+|\/+$/g, '');
  const fileName = String(entry.fileName ?? '')
    .replace(/\\/g, '/')
    .replace(/^\/+/, '');

  if (!fileName || fileName.endsWith('/')) continue;

  const extractedPath = [directory, fileName].filter(Boolean).join('/').replace(/\/+/g, '/');
  if (!extractedPath || extractedPath.endsWith('/')) continue;

  const modulePrefix = moduleName.toLowerCase() + '/';
  const normalizedPath = extractedPath.toLowerCase().startsWith(modulePrefix)
    ? extractedPath
    : moduleName + '/' + extractedPath;

  // Force compression to use this exact relative path.
  const { directory: _ignoredDirectory, ...rest } = entry;
  outputBinary[moduleName + '__' + key] = {
    ...rest,
    fileName: normalizedPath,
  };
}

if (!Object.keys(outputBinary).length) {
  throw new Error('No files were extracted for module: ' + moduleName);
}

return [{ json, binary: outputBinary }];

