const requiredPaths = [
  'requirements/requirements.md',
  'design/design.excalidraw.json',
  'api/openapi.yaml',
];
const fileNames = Object.values(binary).map((entry) => String(entry?.fileName ?? '').replace(/\\/g, '/'));
for (const requiredPath of requiredPaths) {
  if (!fileNames.includes(requiredPath)) {
    throw new Error('Missing required bundle file: ' + requiredPath);
  }
}

const nestedZipMarkers = fileNames.filter((name) =>
  /^(backend|frontend|infrastructure|tests)\/.+\.zip$/i.test(name)
);
if (nestedZipMarkers.length) {
  throw new Error('Nested zip files detected inside module folders: ' + nestedZipMarkers.join(', '));
}

const now = new Date();
const stamp = now.toISOString().replace(/[:.]/g, '-');
const fileName = `application-generation-${stamp}.zip`;

return [{
  json: {
    ...json,
    finalBundleFileName: fileName,
    finalBundleCreatedAt: now.toISOString(),
    finalBundleFolders: ['requirements', 'design', 'api', 'backend', 'frontend', 'infrastructure', 'tests'],
  },
  binary,
}];

const item = $input.first() ?? { json: {}, binary: {} };
const json = item.json ?? {};
const binary = item.binary ?? {};
const zipBinary = binary.masterBundle ?? binary.data;

if (!zipBinary) {
  throw new Error('Final ZIP binary is required before Create ZIP Link.');
}

const archiveData = String(zipBinary.data ?? (zipBinary.id ? 'filesystem-v2' : '')).trim();
const archiveId = String(zipBinary.id ?? '').trim();
const archiveMimeType = String(zipBinary.mimeType ?? 'application/zip').trim() || 'application/zip';
const archiveFileName = String(zipBinary.fileName ?? json.finalBundleFileName ?? 'application-generation.zip').trim() || 'application-generation.zip';

if (!archiveData) {
  throw new Error('Final ZIP binary payload is empty.');
}
if (archiveData === 'filesystem-v2' && !archiveId) {
  throw new Error('Final ZIP id is required for filesystem-backed binary payload.');
}

return [{
  json: {
    ...json,
    archiveData,
    archiveId,
    archiveMimeType,
    archiveFileName,
    archiveBinaryProperty: 'data',
    response: String(json.response ?? 'All module artifacts packed into a final bundle.'),
    revisionNumber: Number(json.revisionNumber ?? 0) || 0,
  },
  binary,
}];
